"""wecomagent SDK 错误类型。"""


class WecomAgentError(Exception):
    """SDK 的根异常类型。所有 SDK 抛出的异常都继承自此类。"""


class NotImplemented(WecomAgentError):  # noqa: A001
    """PR1 阶段的占位异常。PR3/PR4 落地 RPC 后应被替换掉。"""


class RpcError(WecomAgentError):
    """RPC 通信层错误（连接失败 / 协议错误 / 超时）。"""


class PermissionDenied(WecomAgentError):
    """权限不足：审批/配额/白名单拒绝。"""


class QuotaExceeded(WecomAgentError):
    """资源配额用尽（调用次数、字节、耗时等）。"""
